import React, { useState, useEffect } from 'react';
import { Link, useLocation, useNavigate } from 'react-router-dom';
import axios from 'axios';

function Navbar({ user, onLogout, onGenderClick, token }) {
  const location = useLocation();
  const navigate = useNavigate();
  const [cartCount, setCartCount] = useState(0);

  useEffect(() => {
    if (token) {
      fetchCartCount();
    } else {
      // Reset cart count when user logs out
      setCartCount(0);
    }
  }, [token]);

  const fetchCartCount = async () => {
    try {
      const res = await axios.get('/api/cart', {
        headers: { Authorization: `Bearer ${token}` }
      });
      setCartCount(res.data.length || 0);
    } catch (err) {
      console.error('Error fetching cart count:', err);
      setCartCount(0);
    }
  };

  const linkStyle = {
    fontSize: '11px',
    fontWeight: '300',
    fontFamily: 'Helvetica, Arial, sans-serif',
    color: '#000',
    textDecoration: 'none',
    letterSpacing: '0px',
    margin: '0 12px'
  };

  const buttonStyle = {
    ...linkStyle,
    background: 'none',
    border: 'none',
    cursor: 'pointer',
    padding: '0'
  };

  const handleGenderClick = (gender) => {
    const currentPath = location.pathname.toLowerCase();
    const isOnGenderPage = currentPath === '/women' || currentPath === '/men';

    // If on women/men gender page, navigate to the selected gender (view all)
    if (isOnGenderPage) {
      navigate(`/${gender.toLowerCase()}`);
    } else {
      // Otherwise, just open the sidebar for category selection
      if (onGenderClick) {
        onGenderClick(gender);
      }
    }
  };

  return (
    <nav style={{
      display: 'flex',
      justifyContent: 'space-between',
      alignItems: 'center',
      padding: '12px 50px',
      backgroundColor: '#fff',
      borderBottom: '1px solid #f0f0f0',
      fontFamily: 'Helvetica, Arial, sans-serif'
    }}>
      {/* Left Menu */}
      <div style={{ display: 'flex', flex: 1, justifyContent: 'flex-start' }}>
        <button onClick={() => handleGenderClick('WOMEN')} style={buttonStyle}>WOMEN</button>
        <button onClick={() => handleGenderClick('MEN')} style={buttonStyle}>MEN</button>
        <button onClick={() => handleGenderClick('PERFUMERY')} style={buttonStyle}>PERFUMERY</button>
      </div>

      {/* Center - Logo */}
      <div style={{ display: 'flex', flex: 1, justifyContent: 'center' }}>
        <Link to="/" style={{ display: 'flex', alignItems: 'center' }}>
          <img src="/TheRawLogo.svg" alt="Clothing Shop" style={{ height: '35px', width: 'auto' }} />
        </Link>
      </div>

      {/* Right Menu */}
      <div style={{ display: 'flex', flex: 1, justifyContent: 'flex-end', alignItems: 'center' }}>
        <Link to="/" style={linkStyle}>STORES</Link>
        <Link to="/wishlist" style={linkStyle}>SAVED</Link>
        <Link to="/cart" style={{ ...linkStyle, position: 'relative', display: 'inline-block' }}>
          CART
          {cartCount > 0 && (
            <span style={{
              position: 'absolute',
              top: '-8px',
              right: '-14px',
              backgroundColor: '#000',
              color: '#fff',
              width: '15px',
              height: '15px',
              borderRadius: '50%',
              display: 'flex',
              alignItems: 'center',
              justifyContent: 'center',
              fontSize: '10px',
              fontWeight: '600'
            }}>
              {cartCount}
            </span>
          )}
        </Link>
        {user ? (
          <>
            <Link to="/profile" style={linkStyle}>ACCOUNT</Link>
            <Link to="/orders" style={linkStyle}>ORDERS</Link>
            <button onClick={onLogout} style={{ ...linkStyle, background: 'none', border: 'none', cursor: 'pointer', padding: '0' }}>LOGOUT</button>
          </>
        ) : (
          <>
            <Link to="/login" style={linkStyle}>LOGIN</Link>
          </>
        )}
      </div>
    </nav>
  );
}

export default Navbar;
